import $ from 'jquery';
import * as olControl from 'ol/control';
import * as olExtent from 'ol/extent';
import olFeature from 'ol/Feature.js';
import * as olGeometry from 'ol/geom';
import { fromCircle } from 'ol/geom/Polygon';
import olTileLayer from 'ol/layer/Tile';
import olVectorLayer from 'ol/layer/Vector.js';
import olMap from 'ol/Map';
import olOverlay from 'ol/Overlay.js';
import * as olProj from 'ol/proj';
import { get, transform } from 'ol/proj';
import { register } from 'ol/proj/proj4';
import { XYZ } from 'ol/source';
import olVectorSource from 'ol/source/Vector.js';
import * as olStyle from 'ol/style';
import olWMTSTileGrid from 'ol/tilegrid/WMTS.js';
import olView from 'ol/View.js';
import proj4 from 'proj4';

import Draw from 'ol/interaction/Draw.js';
import Modify from 'ol/interaction/Modify.js';
import Select from 'ol/interaction/Select.js';
import Translate from 'ol/interaction/Translate.js';

import * as DateUtil from '@/common/DateUtil';
import * as LogUtil from '@/common/LogUtil';
import * as MapConfigFence from '@/rest/MapConfigFence';

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
        AlertModal,
    },
    data: () => ({
        alertModalParams: { isOpened: false, title: '', message: '' },

        map: null,
        path: '/map/',
        coordDrone: [],
        isModify: false,
        isModifyState: 'default',
        // lineGroup: 1,
        // fillGroup: 1,
        // lineColor: 0,
        // fillColor: 0,
        coordArray: [],
        isLineColorSelected: false,
        isFillColorSelected: false,
        colorList: [
            'red',
            'pink',
            'purple',
            'indigo',
            'blue',
            'light-blue',
            'cyan',
            'teal',
            'green',
            'light-green',
            'lime',
            'yellow',
            'amber',
            'orange',
            'brown',
            'blue-grey',
            'grey',
            'black',
        ],
        colorCodeList: [
            '#F44336',
            '#E91E63',
            '#9C27B0',
            '#3F51B5',
            '#2196F3',
            '#03A9F4',
            '#00BCD4',
            '#009688',
            '#4CAF50',
            '#8BC34A',
            '#CDDC39',
            '#FFEB3B',
            '#FFC107',
            '#FF9800',
            '#795548',
            '#607D8B',
            '#9E9E9E',
            '#000000',
        ],
        fillOpacity: { val: 10, color: '#2a85ff' },

        selectedLineColorIndex: 0,
        selectedFillColorIndex: 0,
        model: {},
    }),
    mounted() {
        this.mapInit();
        this.initDataList();
    },
    methods: {
        showAlertModal(msg) {
            this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
        },
        doClickLineColor() {
            this.isLineColorSelected = !this.isLineColorSelected;
        },
        doSelectLineColor(index) {
            this.isLineColorSelected = false;
            this.selectedLineColorIndex = index;
        },
        doClickFilleColor() {
            this.isFillColorSelected = !this.isFillColorSelected;
        },
        doSelectFillColor(index) {
            this.isFillColorSelected = false;
            this.selectedFillColorIndex = index;
        },
        initDataList(condition) {
            let options = {
                conditions: [
                    // { clause: 'and', name: 'CONFIG_TYPE', operator: '=', value: 'D'},
                ],
                orderBys: [{ name: 'MAP_CONFIG_FENCE_ID', operator: 'asc' }],
                paging: { pageNo: 1, pageSize: 100 },
            };
            if (condition != null) options.conditions.push(condition);

            MapConfigFence.listByCondition(options)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        this.model =
                            res.data.ITEMS.length > 0
                                ? res.data.ITEMS[0]
                                : {
                                      MAP_CONFIG_FENCE_ID: -1,
                                      LINE_TYPE: 1,
                                      LINE_WIDTH: 20,
                                      LINE_COLOR: 'red',
                                      FILL_TYPE: 1,
                                      FILL_COLOR: 'lime',
                                      FILL_TRANSPARENCY: 10,
                                      POLIGON: null,
                                      COORDINATE: null,
                                      CREATED: null,
                                  };
                        LogUtil.debug(
                            'MapFence: initDataList(): this.colorCodeList[this.colorList.indexOf(this.model.LINE_COLOR)]=',
                            this.colorCodeList[this.colorList.indexOf(this.model.LINE_COLOR)],
                        );
                        LogUtil.debug(
                            'MapFence: initDataList(): this.colorCodeList[this.colorList.indexOf(this.model.FILL_COLOR)]=',
                            this.colorCodeList[this.colorList.indexOf(this.model.FILL_COLOR)],
                        );
                        LogUtil.debug('MapFence: initDataList(): this.model=', this.model);

                        this.selectedLineColorIndex = this.colorList.indexOf(this.model.LINE_COLOR);
                        this.selectedFillColorIndex = this.colorList.indexOf(this.model.FILL_COLOR);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
        doSave() {
            // let model = {
            //   // MAP_CONFIG_CIRCLE_ID: this.model.MAP_CONFIG_CIRCLE_ID,
            //   // RADIUS_NAME: this.model.RADIUS_NAME,
            //   // RADIUS: this.model.RADIUS,
            //   // LINE_TYPE: this.model.LINE_TYPE,
            //   LINE_COLOR: this.colorList[this.selectedLineColorIndex],
            //   LINE_WIDTH: this.model.LINE_WIDTH,
            //   FILL_TYPE: this.model.FILL_TYPE,
            //   FILL_COLOR: this.colorList[this.selectedFillColorIndex],
            //   FILL_TRANSPARENCY: this.model.FILL_TRANSPARENCY,
            //   DISPLAY_TYPE: this.model.DISPLAY_TYPE,
            //   WARNING_TYPE: this.model.WARNING_TYPE,
            //   CREATED: this.model.CREATED != null ? DateUtil.getTimestamp(this.model.CREATED) : DateUtil.getCurrentTimestamp(),
            //   UPDATED: DateUtil.getCurrentTimestamp(),
            // }

            this.model.LINE_COLOR = this.colorList[this.selectedLineColorIndex];
            this.model.FILL_COLOR = this.colorList[this.selectedFillColorIndex];
            this.model.CREATED = this.model.CREATED != null ? DateUtil.getTimestamp(this.model.CREATED) : DateUtil.getCurrentTimestamp();
            this.model.UPDATED = DateUtil.getCurrentTimestamp();

            LogUtil.debug('MapFence: doSave(): this.model=', this.model);
            MapConfigFence.save(this.model)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        LogUtil.debug('MapFence: doSave(): res.data=', res.data);
                        if (this.model.MAP_CONFIG_FENCE_ID === -1) {
                            this.model.MAP_CONFIG_FENCE_ID = res.data.ITEM.insertId;
                        }
                        LogUtil.debug('MapFence: doSave(): this.model.MAP_CONFIG_FENCE_ID=', this.model.MAP_CONFIG_FENCE_ID);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },

        modifyState(value) {
            const start = value === 'start';
            if (start) {
                this.map
                    .getLayers()
                    .getArray()
                    .slice(0)
                    .find((__) => __.get('name') == 'vectorPoligon')
                    .getSource()
                    .clear();
            }
            this.isModify = start;
        },
        mapInit() {
            proj4.defs(
                'EPSG:5179',
                '+proj=tmerc +lat_0=38 +lon_0=127.5 +k=0.9996 +x_0=1000000 +y_0=2000000 +ellps=GRS80 +towgs84=0,0,0,0,0,0,0 +units=m +no_defs +type=crs',
            );
            register(proj4);

            const EPSG_5179 = get('EPSG:5179');
            EPSG_5179.setExtent([-200000.0, -28024123.62, 31824123.62, 4000000.0]);
            EPSG_5179.getTileGrid = () =>
                new olWMTSTileGrid({
                    origin: olExtent.getTopLeft(EPSG_5179.getExtent()),
                    resolutions: [2088.96, 1044.48, 522.24, 261.12, 130.56, 65.28, 32.64, 16.32, 8.16, 4.08, 2.04, 1.02, 0.51, 0.255],
                });

            // 랜드오버 위도/경도
            const lat = 37.4862285;
            const lng = 126.9631919;

            this.map = new olMap({
                target: 'map',
                controls: olControl.defaults({ zoom: false, attribution: false }).extend([new olControl.ScaleLine({ units: 'metric' })]),
                layers: [
                    // 국토정보지리원 바로e맵 좌표계는 EPSG:5179
                    new olTileLayer({
                        source: new XYZ({
                            attributions: '구현 UI 샘플',
                            projection: EPSG_5179,
                            tileGrid: EPSG_5179.getTileGrid(),
                            tileUrlFunction: (coordinate) => {
                                // 줌레벨보정계수 5
                                const z = coordinate[0] + 5;
                                const x = coordinate[1];
                                const y = coordinate[2];
                                // [LOCAL-MODE] 초기 레이어를 일반지도(korean_map)로 변경.
                                return `https://map.ngii.go.kr/openapi/Gettile.do?apikey=0DCCF3037745F67F165F35B3626FA83F&layer=korean_map&style=korean&tilematrixset=EPSG%3A5179&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fpng&TileMatrix=L${String(z).padStart(2, '0')}&TileCol=${x}&TileRow=${y}`;
                            },
                        }),
                        name: 'ngii-emap',
                    }),

                    new olVectorLayer({
                        source: new olVectorSource(),
                        style: {
                            'fill-color': 'rgba(255, 255, 255, 0.7)',
                            'stroke-color': '#ffcc33',
                            'stroke-width': 2,
                            'circle-radius': 7,
                            'circle-fill-color': '#ffcc33',
                        },
                        name: 'vector',
                    }),
                    // 다각형 레이어
                    new olVectorLayer({
                        source: new olVectorSource(),
                        opacity: this.fillOpacity.val * 0.1,

                        style: {
                            'fill-color': this.model.FILL_TYPE === 0 ? 'transparent' : '#FFEB3B', // this.colorCodeList[this.colorList.indexOf(this.model.FILL_COLOR)],
                            'stroke-color': '#F44336', // this.colorCodeList[this.colorList.indexOf(this.model.LINE_COLOR)],
                            'stroke-width': this.model.LINE_TYPE === 1 ? this.model.LINE_WIDTH : 0,
                        },
                        name: 'vectorPoligon',
                    }),
                ],

                // openlayers 기본 좌표계는 EPSG:3857 ( EPSG:5179로 변경 )
                view: new olView({
                    constrainResolution: true,
                    projection: EPSG_5179,
                    maxResolution: EPSG_5179.getTileGrid().getResolutions()[0],
                    minResolution: EPSG_5179.getTileGrid().getResolutions().slice(-1),
                    extent: EPSG_5179.getExtent(),

                    center: transform([lng, lat], 'EPSG:4326', 'EPSG:5179'),
                    zoom: 6, // 0 ~ 13
                }),
            });

            setTimeout(() => {
                this.drawRadar();
            }, 100);
        },
        drawRadar() {
            // 레이다 중심 좌표
            const center = olProj.transform([126.959598, 37.485113], 'EPSG:4326', 'EPSG:5179');

            // 레이다 원 정보 ( 반지름, 반지름텍스트{좌,우,상,하}, 선색상 )
            const radar_info = [
                [500, '500m', '500m', '500m', '심각 500m', '#ff0000'],
                [1000, '1km', '1km', '1km', '경계 1km', '#ff8000'],
                [2000, '2km', '2km', '2km', '주의 2km', '#ffff00'],
                [3000, '3km', '3km', '3km', '관심 2km', '#0066cc'],
            ];

            const vectorSource = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'vector')
                .getSource();

            // 레이다 라인 표시
            {
                const radius = radar_info[radar_info.length - 1][0];
                [
                    [0, 180],
                    [45, 225],
                    [90, 270],
                    [135, 315],
                ].forEach((angle) => {
                    const start_x = center[0] + radius * Math.cos((angle[0] / 180) * Math.PI);
                    const start_y = center[1] + radius * Math.sin((angle[0] / 180) * Math.PI);
                    const end_x = center[0] + radius * Math.cos((angle[1] / 180) * Math.PI);
                    const end_y = center[1] + radius * Math.sin((angle[1] / 180) * Math.PI);

                    const feature = new olFeature(
                        new olGeometry.LineString([
                            [start_x, start_y],
                            [end_x, end_y],
                        ]),
                    );
                    feature.setStyle(
                        new olStyle.Style({
                            stroke: new olStyle.Stroke({ color: 'white', width: 1 }),
                        }),
                    );

                    vectorSource.addFeature(feature);
                });
            }

            // 심각 5각형 표시
            // {
            //     const radius = radar_info[0][0] * 1.2360700000002363;
            //     const circle = new olGeometry.Circle(center, radius);
            //     const polygon = fromCircle(circle, 5, (18 / 180) * Math.PI);

            //     const feature = new olFeature(polygon);
            //     feature.setStyle(
            //         new olStyle.Style({
            //             stroke: new olStyle.Stroke({ color: 'white', width: 3 }),
            //         }),
            //     );

            //     vectorSource.addFeature(feature);
            // }

            radar_info.forEach((radar) => {
                // 원 표시
                {
                    const circle = new olGeometry.Circle(center, radar[0]);
                    const polygon = fromCircle(circle, 99, 0);

                    const feature = new olFeature(polygon);
                    feature.setId(`radar-${String(radar[0]).padStart(9, '0')}`);
                    feature.setStyle(
                        new olStyle.Style({
                            stroke: new olStyle.Stroke({ color: radar[5], width: 3 }),
                        }),
                    );

                    vectorSource.addFeature(feature);
                }

                // 반지름 표시 ( 각도, 정렬, 텍스트 )
                [
                    ['180', 'center-left', radar[1] + '<br/><br/>'],
                    ['0', 'center-right', radar[2] + '<br/><br/>'],
                    ['90', 'top-center', radar[3]],
                    ['270', 'bottom-center', radar[4]],
                ].forEach((pos) => {
                    const x = center[0] + radar[0] * Math.cos((pos[0] / 180) * Math.PI);
                    const y = center[1] + radar[0] * Math.sin((pos[0] / 180) * Math.PI);

                    const marker = new olOverlay({
                        position: [x, y],
                        positioning: pos[1],
                        element: $(`<small style='color:white; cursor:default;'>${pos[2]}</small>`)[0],
                        stopEvent: false,
                    });
                    this.map.addOverlay(marker);
                });
            });

            // 레이다 중심 포인트 표시
            {
                const feature = new olFeature(new olGeometry.Point(center));
                feature.setStyle(
                    new olStyle.Style({
                        image: new olStyle.Circle({
                            radius: 8,
                            fill: new olStyle.Fill({ color: 'white' }),
                        }),
                    }),
                );

                vectorSource.addFeature(feature);
            }

            this.map.getView().fit(vectorSource.getExtent(), { duration: 200 });
        },
        selectPolygon(value) {
            // 기존 interaction 모두 제거
            this.map
                .getInteractions()
                .getArray()
                .slice(0)
                .forEach((interaction) => {
                    if (
                        interaction instanceof Draw ||
                        interaction instanceof Modify ||
                        interaction instanceof Select ||
                        interaction instanceof Translate
                    ) {
                        this.map.removeInteraction(interaction);
                    }
                });
            this.isModifyState = 'default';
            this.coordArray = [];
            if ('default' === value) return;
            if ('draw' === value) {
                this.isModifyState = 'draw';
                // 다각형 그리기
                const draw = new Draw({
                    source: this.map
                        .getLayers()
                        .getArray()
                        .slice(0)
                        .find((__) => __.get('name') == 'vectorPoligon')
                        .getSource(),
                    type: 'Polygon', // LineString, Polygon
                });
                this.map.addInteraction(draw);
                draw.on('drawend', (event) => {
                    this.selectPolygon('default');
                });
            } else if ('modify' === value) {
                this.isModifyState = 'modify';
                // 꼭지점삭제 ( ALT+꼭지점클릭 )
                this.map.addInteraction(
                    new Modify({
                        source: this.map
                            .getLayers()
                            .getArray()
                            .slice(0)
                            .find((__) => __.get('name') == 'vectorPoligon')
                            .getSource(),
                    }),
                );
                var select;
                this.map.addInteraction(
                    (select = new Select({
                        layers: [
                            this.map
                                .getLayers()
                                .getArray()
                                .slice(0)
                                .find((__) => __.get('name') == 'vectorPoligon'),
                        ],
                    })),
                );
                this.map.addInteraction(new Translate({ features: select.getFeatures() }));
            } else if ('clear' === value) {
                // 전체 다각형 삭제
                this.map
                    .getLayers()
                    .getArray()
                    .slice(0)
                    .find((__) => __.get('name') == 'vectorPoligon')
                    .getSource()
                    .clear();
            } else if ('coord' === value) {
                // 다각형의 좌표 출력
                const map = this.map
                    .getLayers()
                    .getArray()
                    .slice(0)
                    .find((__) => __.get('name') == 'vectorPoligon')
                    .getSource();
                map.getFeatures().forEach((feature, idx) => {
                    const coord_epsg4326 = feature.getGeometry().clone().transform('EPSG:5179', 'EPSG:4326').getCoordinates();
                    this.coordArray[idx] = coord_epsg4326[0];
                    this.coordArray[idx].pop();
                });
            }
        },
    },
};
